render(createElement, context) {
  const data = {
    props: {
      mode: 'out-in'
    },
    on: {
      beforeEnter(el) {
        el.style.opacity = 0.2;
      },

      enter(el) {
        addClass(el, 'el-opacity-transition');
        el.style.opacity = 1;
      },

      afterEnter(el) {
        removeClass(el, 'el-opacity-transition');
        el.style.opacity = '';
      },

      beforeLeave(el) {
        if (!el.dataset) el.dataset = {};

        if (hasClass(el, 'el-menu--collapse')) {
          removeClass(el, 'el-menu--collapse');
          el.dataset.oldOverflow = el.style.overflow;
          el.dataset.scrollWidth = el.clientWidth;
          addClass(el, 'el-menu--collapse');
        } else {
          addClass(el, 'el-menu--collapse');
          el.dataset.oldOverflow = el.style.overflow;
          el.dataset.scrollWidth = el.clientWidth;
          removeClass(el, 'el-menu--collapse');
        }

        el.style.width = el.scrollWidth + 'px';
        el.style.overflow = 'hidden';
      },

      leave(el) {
        addClass(el, 'horizontal-collapse-transition');
        el.style.width = el.dataset.scrollWidth + 'px';
      }
    }
  };
  return createElement('transition', data, context.children);
}

import { RawFormSchema, validateObject, validate, GenericObject } from 'vee-validate';
import { StandardSchemaV1 } from '@standard-schema/spec';

export function toTypedSchema<TInput, TOutput = TInput>(
  rawSchema: RawFormSchema<TInput> | string,
): StandardSchemaV1<TInput, TOutput> {
  const schema: StandardSchemaV1<TInput, TOutput> = {
    '~standard': {
      vendor: 'vee-validate',
      version: 1,
      async validate(values: unknown) {
        if (typeof rawSchema === 'string') {
          const result = await validate(values, rawSchema);

          return {
            issues: result.errors.map(error => ({
              path: [],
              message: error,
            })),
          };
        }

        const result = await validateObject(rawSchema, values as GenericObject | undefined);
        const issues: StandardSchemaV1.Issue[] = [];
        if (result.valid) {
          return {
            value: result.values as TOutput,
          };
        }

        for (const [path, error] of Object.entries(result.errors)) {
          if (error) {
            issues.push({
              path: [path],
              message: error,
            });
          }
        }

        return {
          issues,
        };
      },
    },
  };

  return schema;
}

import { compile, match } from 'path-to-regexp'
import type { Plugin } from 'vite'
import type { SiteConfig, UserConfig } from '../siteConfig'

export function resolveRewrites(
  pages: string[],
  userRewrites: UserConfig['rewrites']
) {
  const pageToRewrite: Record<string, string> = {}
  const rewriteToPage: Record<string, string> = {}

  if (typeof userRewrites === 'function') {
    for (const page of pages) {
      const dest = userRewrites(page)
      if (dest && dest !== page) {
        pageToRewrite[page] = dest
        rewriteToPage[dest] = page
      }
    }
  } else if (typeof userRewrites === 'object') {
    const rewriteRules = Object.entries(userRewrites || {}).map(
      ([from, to]) => ({
        toPath: compile(`/${to}`, { validate: false }),
        matchUrl: match(from.startsWith('^') ? new RegExp(from) : from)
      })
    )

    if (rewriteRules.length) {
      for (const page of pages) {
        for (const { matchUrl, toPath } of rewriteRules) {
          const res = matchUrl(page)
          if (res) {
            const dest = toPath(res.params).slice(1)
            pageToRewrite[page] = dest
            rewriteToPage[dest] = page
            break
          }
        }
      }
    }
  }

  return {
    map: pageToRewrite,
    inv: rewriteToPage
  }
}

export function stackView<T extends ObjectType>(..._layers: Partial<T>[]): T {
  const layers = _layers.filter((layer) => isObject(layer))
  if (layers.length <= 1) return _layers[0] as T

  const allKeys = new Set(layers.flatMap((layer) => Reflect.ownKeys(layer)))
  const allKeysArray = [...allKeys]

  return new Proxy({} as T, {
    // TODO: optimize for performance, this is a hot path
    get(_, prop) {
      if (prop === UnpackStackView) return layers
      return stackView(
        ...layers
          .map((layer) => layer[prop])
          .filter((v): v is NonNullable<T[string | symbol]> => v !== undefined)
      )
    },
    set() {
      throw new Error('StackView is read-only and cannot be mutated.')
    },
    has(_, prop) {
      return allKeys.has(prop)
    },
    ownKeys() {
      return allKeysArray
    },
    getOwnPropertyDescriptor(_, prop) {
      for (const layer of layers) {
        const descriptor = Object.getOwnPropertyDescriptor(layer, prop)
        if (descriptor) return descriptor
      }
    }
  })
}

stackView.unpack = function <T>(obj: T): T[] | undefined {
  return (obj as any)?.[UnpackStackView]
}

export function fromXYZ (xyz: XYZ): RGB {
  const rgb = Array(3)
  const transform = srgbForwardTransform
  const matrix = srgbForwardMatrix

  // Matrix transform, then gamma adjustment
  for (let i = 0; i < 3; ++i) {
    // Rescale back to [0, 255]
    rgb[i] = Math.round(clamp(transform(
      matrix[i][0] * xyz[0] +
      matrix[i][1] * xyz[1] +
      matrix[i][2] * xyz[2]
    )) * 255)
  }

  return {
    r: rgb[0],
    g: rgb[1],
    b: rgb[2],
  }
}

export function toXYZ ({ r, g, b }: RGB): XYZ {
  const xyz: XYZ = [0, 0, 0]
  const transform = srgbReverseTransform
  const matrix = srgbReverseMatrix

  // Rescale from [0, 255] to [0, 1] then adjust sRGB gamma to linear RGB
  r = transform(r / 255)
  g = transform(g / 255)
  b = transform(b / 255)

  // Matrix color space transform
  for (let i = 0; i < 3; ++i) {
    xyz[i] = matrix[i][0] * r + matrix[i][1] * g + matrix[i][2] * b
  }

  return xyz
}

makeOcRequest(cb, params = {}) {
  // Merge given params with defaults
  params = { ...OC_DEFAULT_PARAMS, ...params }
  // Build the query
  const query = Object.keys(params).reduce(
    (query, key) => (params[key] ? `${query}${query ? '&' : ''}${key}=${params[key]}` : query),
    ''
  )

  const url = `${OC_BASE_URL}?${query}`
  const xhr = new XMLHttpRequest()

  const onLoad = () => {
    if (xhr.readyState !== 4) {
      return
    }
    if (xhr.status === 200) {
      const response = JSON.parse(xhr.responseText) || {}
      cb(this.processOcNodes(response.nodes || []), null)
    } else {
      // We just return an empty node list rather than spew an error
      // eslint-disable-next-line node/no-callback-literal
      cb([], xhr.statusText)
    }
  }

  xhr.open('GET', url, true)
  xhr.addEventListener('load', onLoad, {
    signal: this.controller ? this.controller.signal : undefined
  })
  // Initiate the request
  xhr.send()
}

setValues(newValue: number | number[]) {
    if (this.min > this.max) {
        return
    }
    if (Array.isArray(newValue)) {
        this.isRange = true
        const smallValue = typeof newValue[0] !== 'number' || isNaN(newValue[0])
            ? this.min
            : bound(newValue[0], this.min, this.max)
        const largeValue = typeof newValue[1] !== 'number' || isNaN(newValue[1])
            ? this.max
            : bound(newValue[1], this.min, this.max)
        // premature update will be triggered and end up with circular
        // update, if value1 and value2 are updated one by one
        this.internal = {
            value1: this.isThumbReversed ? largeValue : smallValue,
            value2: this.isThumbReversed ? smallValue : largeValue
        }
    } else {
        this.isRange = false
        this.internal = {
            value1: isNaN(newValue)
                ? this.min
                : bound(newValue, this.min, this.max),
            value2: undefined
        }
    }
}

trackMouse(event: MouseEvent | TouchEvent) {
    if (this.captureMouse === false) {
        return
    }
    event.preventDefault()
    event.stopPropagation()

    const touches = (event as TouchEvent).touches
    let [mouseX, mouseY] = [0, 0]
    if (typeof touches !== 'undefined' && touches.length) {
        [mouseX, mouseY] = [touches[0].clientX, touches[0].clientY]
    } else {
        [mouseX, mouseY] = [(event as MouseEvent).clientX, (event as MouseEvent).clientY]
    }
    const angle = Math.atan2(
        mouseY - this.clientOffset.cy,
        mouseX - this.clientOffset.cx
    )

    if (this.captureType === 'sl') {
        const saturation = (mouseX - this.clientOffset.cx) /
            (this.clientOffset.width - this.thickness * 2) +
            0.5
        const lightness = (mouseY - this.clientOffset.cy) /
            (this.clientOffset.height - this.thickness * 2) +
            0.5

        this.saturation = Math.round(Math.min(1, Math.max(0, saturation)) * 1000) / 1000
        this.lightness = 1 - Math.round(Math.min(1, Math.max(0, lightness)) * 1000) / 1000
    } else {
        this.hue = Math.round(angle / Math.PI * 180 + 90) % 360
    }
    this.emitColor()
}

handleKeyControl(keyCode) {
  const mapping = {
    'year': {
      38: -4, 40: 4, 37: -1, 39: 1, offset: (date, step) => date.setFullYear(date.getFullYear() + step)
    },
    'month': {
      38: -4, 40: 4, 37: -1, 39: 1, offset: (date, step) => date.setMonth(date.getMonth() + step)
    },
    'week': {
      38: -1, 40: 1, 37: -1, 39: 1, offset: (date, step) => date.setDate(date.getDate() + step * 7)
    },
    'day': {
      38: -7, 40: 7, 37: -1, 39: 1, offset: (date, step) => date.setDate(date.getDate() + step)
    }
  };
  const mode = this.selectionMode;
  const year = 3.1536e10;
  const now = this.date.getTime();
  const newDate = new Date(this.date.getTime());
  while (Math.abs(now - newDate.getTime()) <= year) {
    const map = mapping[mode];
    map.offset(newDate, map[keyCode]);
    if (typeof this.disabledDate === 'function' && this.disabledDate(newDate)) {
      continue;
    }
    this.date = newDate;
    this.$emit('pick', newDate, true);
    break;
  }
}

upload(rawFile) {
  this.$refs.input.value = null;

  if (!this.beforeUpload) {
    return this.post(rawFile);
  }

  const before = this.beforeUpload(rawFile);
  if (before && before.then) {
    before.then(processedFile => {
      const fileType = Object.prototype.toString.call(processedFile);

      if (fileType === '[object File]' || fileType === '[object Blob]') {
        if (fileType === '[object Blob]') {
          processedFile = new File([processedFile], rawFile.name, {
            type: rawFile.type
          });
        }
        for (const p in rawFile) {
          if (rawFile.hasOwnProperty(p)) {
            processedFile[p] = rawFile[p];
          }
        }
        this.post(processedFile);
      } else {
        this.post(rawFile);
      }
    }, () => {
      this.onRemove(null, rawFile);
    });
  } else if (before !== false) {
    this.post(rawFile);
  } else {
    this.onRemove(null, rawFile);
  }
}

deviceSupportInstall() {
  this._keyDownHandler = e => {
    e.stopPropagation();
    const keyCode = e.keyCode;
    switch (keyCode) {
      // ESC
      case 27:
        this.hide();
        break;
      // SPACE
      case 32:
        this.toggleMode();
        break;
      // LEFT_ARROW
      case 37:
        this.prev();
        break;
      // UP_ARROW
      case 38:
        this.handleActions('zoomIn');
        break;
      // RIGHT_ARROW
      case 39:
        this.next();
        break;
      // DOWN_ARROW
      case 40:
        this.handleActions('zoomOut');
        break;
    }
  };
  this._mouseWheelHandler = rafThrottle(e => {
    const delta = e.wheelDelta ? e.wheelDelta : -e.detail;
    if (delta > 0) {
      this.handleActions('zoomIn', {
        zoomRate: 0.015,
        enableTransition: false
      });
    } else {
      this.handleActions('zoomOut', {
        zoomRate: 0.015,
        enableTransition: false
      });
    }
  });
  on(document, 'keydown', this._keyDownHandler);
  on(document, mousewheelEventName, this._mouseWheelHandler);
}

pagers() {
  const pagerCount = this.pagerCount;
  const halfPagerCount = (pagerCount - 1) / 2;

  const currentPage = Number(this.currentPage);
  const pageCount = Number(this.pageCount);

  let showPrevMore = false;
  let showNextMore = false;

  if (pageCount > pagerCount) {
    if (currentPage > pagerCount - halfPagerCount) {
      showPrevMore = true;
    }

    if (currentPage < pageCount - halfPagerCount) {
      showNextMore = true;
    }
  }

  const array = [];

  if (showPrevMore && !showNextMore) {
    const startPage = pageCount - (pagerCount - 2);
    for (let i = startPage; i < pageCount; i++) {
      array.push(i);
    }
  } else if (!showPrevMore && showNextMore) {
    for (let i = 2; i < pagerCount; i++) {
      array.push(i);
    }
  } else if (showPrevMore && showNextMore) {
    const offset = Math.floor(pagerCount / 2) - 1;
    for (let i = currentPage - offset ; i <= currentPage + offset; i++) {
      array.push(i);
    }
  } else {
    for (let i = 2; i < pageCount; i++) {
      array.push(i);
    }
  }

  this.showPrevMore = showPrevMore;
  this.showNextMore = showNextMore;

  return array;
}

get() {
  let style = {};
  let offset = 0;
  let tabSize = 0;
  const sizeName = ['top', 'bottom'].indexOf(this.rootTabs.tabPosition) !== -1 ? 'width' : 'height';
  const sizeDir = sizeName === 'width' ? 'x' : 'y';
  const firstUpperCase = str => {
    return str.toLowerCase().replace(/( |^)[a-z]/g, (L) => L.toUpperCase());
  };
  this.tabs.every((tab, index) => {
    let $el = arrayFind(this.$parent.$refs.tabs || [], t => t.id.replace('tab-', '') === tab.paneName);
    if (!$el) { return false; }

    if (!tab.active) {
      offset += $el[`client${firstUpperCase(sizeName)}`];
      return true;
    } else {
      tabSize = $el[`client${firstUpperCase(sizeName)}`];
      const tabStyles = window.getComputedStyle($el);
      if (sizeName === 'width' && this.tabs.length > 1) {
        tabSize -= parseFloat(tabStyles.paddingLeft) + parseFloat(tabStyles.paddingRight);
      }
      if (sizeName === 'width') {
        offset += parseFloat(tabStyles.paddingLeft);
      }
      return false;
    }
  });

  const transform = `translate${firstUpperCase(sizeDir)}(${offset}px)`;
  style[sizeName] = tabSize + 'px';
  style.transform = transform;
  style.msTransform = transform;
  style.webkitTransform = transform;

  return style;
}

(
    el: HTMLElement,
    options: Sortable.Options,
    taginput: BTaginputInstance
) => {
    return Sortable.create(el, {
        ...options,
        onEnd: function (evt) {
            const data = taginput.$data.tags;
            const item = data[evt.oldIndex!];
            if (evt.newIndex! > evt.oldIndex!) {
                for (let i = evt.oldIndex!; i < evt.newIndex!; i++) {
                    data[i] = data[i + 1];
                }
            } else {
                for (let i = evt.oldIndex!; i > evt.newIndex!; i--) {
                    data[i] = data[i - 1];
                }
            }
            data[evt.newIndex!] = item;
            taginput.$emit("update:modelValue", data);
            taginput.$buefy.toast.open(
                `Moved ${item} from row ${evt.oldIndex! + 1} to ${
                    evt.newIndex! + 1
                }`
            );
        },
    });
}

computedData(): DataItem[] {
    const { groupField, groupOptions } = this
    if (groupField) {
        if (groupOptions) {
            const newData: DataItem[] = []
            this.data.forEach((option) => {
                const group = getValueByPath(option, groupField)
                const items = getValueByPath(option, groupOptions)
                newData.push({ group, items })
            })
            return newData
        } else {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const tmp: Record<string, any[]> = {}
            this.data.forEach((option) => {
                const group = getValueByPath(option, groupField)
                if (!tmp[group]) tmp[group] = []
                tmp[group].push(option)
            })
            const newData: DataItem[] = []
            Object.keys(tmp).forEach((group) => {
                newData.push({ group, items: tmp[group] })
            })
            return newData
        }
    }
    return [{ items: this.data }]
}

function(id, zIndex, dom, modalClass, modalFade) {
  if (Vue.prototype.$isServer) return;
  if (!id || zIndex === undefined) return;
  this.modalFade = modalFade;

  const modalStack = this.modalStack;

  for (let i = 0, j = modalStack.length; i < j; i++) {
    const item = modalStack[i];
    if (item.id === id) {
      return;
    }
  }

  const modalDom = getModal();

  addClass(modalDom, 'v-modal');
  if (this.modalFade && !hasModal) {
    addClass(modalDom, 'v-modal-enter');
  }
  if (modalClass) {
    let classArr = modalClass.trim().split(/\s+/);
    classArr.forEach(item => addClass(modalDom, item));
  }
  setTimeout(() => {
    removeClass(modalDom, 'v-modal-enter');
  }, 200);

  if (dom && dom.parentNode && dom.parentNode.nodeType !== 11) {
    dom.parentNode.appendChild(modalDom);
  } else {
    document.body.appendChild(modalDom);
  }

  if (zIndex) {
    modalDom.style.zIndex = zIndex;
  }
  modalDom.tabIndex = 0;
  modalDom.style.display = '';

  this.modalStack.push({ id: id, zIndex: zIndex, modalClass: modalClass });
}

function findCodeBlocks(docText: string): CodeBlockInfo[] {
  const lines = docText.split(RE_NEWLINE)
  const codeBlocks: CodeBlockInfo[] = []

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i]
    const trimmedLine = line.trimStart()

    if (trimmedLine.startsWith('```')) {
      const indent = line.length - trimmedLine.length
      const codeBlockLevel = line.match(RE_LEADING_BACKTICKS)![0]
      const backtickCount = codeBlockLevel.trim().length
      const startLine = i

      if (backtickCount !== 3) {
        continue
      }

      let endLine = i
      for (let j = i + 1; j < lines.length; j++) {
        if (lines[j].startsWith(codeBlockLevel)) {
          endLine = j
          break
        }
      }

      if (endLine > startLine) {
        codeBlocks.push({
          startLine: startLine + 1,
          endLine,
          indent,
        })
      }

      i = endLine
    }
  }

  return codeBlocks
}

